cd /workspace && python3 -c "
from docx import Document
doc = Document('output/mkpoly-jva-compromise-provisions.docx')
paras = [p.text for p in doc.paragraphs if p.text.strip()]
# Search for key terms to check presence
terms = ['forum-selection','forum selection','scaling','500,000','de minimis','24 months preceding','Polaris','Endurance','Trident','PPG','Sherwin','4,785','50.52','California','16602.5','Chancery','Harris County','reformation','blue-pencil','EDIX','Boulden','Marsh','Peat Marwick','BDO Seidman','Edwards','intra-group','wholly owned Affiliate','EUR','euro','SOFR','Cure Loan','transitional','Transitional','improvements','Improvements','25%','twenty-five','audit','Audit','collar','Collar','baseball','Baseball','no minority','marketability','deadlock','Deadlock','involuntary','Involuntary','change of control','Change of Control','material breach','Material Breach']
for t in terms:
    found = any(t.lower() in p.lower() for p in paras)
    # also check tables
    if not found:
        for tb in doc.tables:
            for r in tb.rows:
                for c in r.cells:
                    if t.lower() in c.text.lower():
                        found = True
                        break
    print(f'{\"FOUND   \" if found else \"MISSING \"} : {t}')
"

cd /workspace && ls -la output/mkpoly-jva-compromise-provisions.docx && python3 skills/docx/scripts/validate.py output/mkpoly-jva-compromise-provisions.docx 2>&1 && echo "---word count---" && python3 -c "
from docx import Document
doc = Document('output/mkpoly-jva-compromise-provisions.docx')
words = sum(len(p.text.split()) for p in doc.paragraphs)
for t in doc.tables:
    for r in t.rows:
        for c in r.cells:
            words += len(c.text.split())
print('Approximate word count:', words)
"
